from __future__ import annotations

import json
import re
import sys
import unicodedata
from itertools import combinations

sys.path.insert(0, "G:/Github/installed-persona-study")

from harness.polos_sujeito import (ItemEscolha, pontua_sujeito, SUJEITOS_DEGENERADOS,
                                   sup_comprimento)

CAM = ("C:/Users/%USERNAME%/AppData/Local/Temp/claude/"
       "G--Github-GomesARCH-meta/3ca81f38-4117-4369-9f2e-a0439511446c/"
       "scratchpad/v1_nao_generico.jsonl")

itens = []
with open(CAM, encoding="utf-8") as fh:
    for linha in fh:
        linha = linha.strip()
        if not linha:
            continue
        d = json.loads(linha)
        itens.append(ItemEscolha(item_id=d["item_id"], contexto=d["contexto"],
                                 op_consistente=d["op_consistente"],
                                 op_violadora=d["op_violadora"],
                                 intensificador_em=d.get("intensificador_em", ""),
                                 invariante=d.get("invariante", ""),
                                 polo=d.get("polo", "")))


def sa(t: str) -> str:
    t = unicodedata.normalize("NFD", t.lower())
    return "".join(c for c in t if unicodedata.category(c) != "Mn")


def pal(t: str) -> list[str]:
    return re.findall(r"[a-z]+", sa(t))


def cauda(a: str, b: str) -> tuple[list[str], list[str]]:
    """Parte divergente: descarta o prefixo comum de palavras."""
    pa, pb = pal(a), pal(b)
    i = 0
    while i < min(len(pa), len(pb)) and pa[i] == pb[i]:
        i += 1
    return pa[i:], pb[i:]


def escolhe(va: float, vb: float, maior=True) -> str:
    """Prefere o maior (ou menor). Empate -> '1', que SEMPRE falha o criterio E."""
    if va == vb:
        return "1"
    if maior:
        return "1" if va > vb else "2"
    return "1" if va < vb else "2"


# ---------------------------------------------------------------- heuristicas
def h_conta(termos, maior=True, so_cauda=False, nome=None):
    st = set(termos)

    def f(ctx, a, b):
        pa, pb = (cauda(a, b) if so_cauda else (pal(a), pal(b)))
        return escolhe(sum(w in st for w in pa), sum(w in st for w in pb), maior)
    f.__name__ = nome or "conta"
    return f


def h_regex(patt, maior=True, nome=None):
    r = re.compile(patt)

    def f(ctx, a, b):
        return escolhe(len(r.findall(sa(a))), len(r.findall(sa(b))), maior)
    f.__name__ = nome or "regex"
    return f


def possessivo(ctx, a, b):
    """Prefere a opcao com mais marcas de 1a pessoa possessiva."""
    st = {"meu", "meus", "minha", "minhas", "mim", "me", "comigo"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)))


def possessivo_estrito(ctx, a, b):
    st = {"meu", "meus", "minha", "minhas"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)))


def modo_jeito(ctx, a, b):
    """Prefere a opcao que contem um substantivo de MANEIRA."""
    st = {"modo", "jeito", "maneira", "estilo"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)))


def infinitivo_final(ctx, a, b):
    """Prefere a opcao cuja ultima palavra e' infinitivo (-ar/-er/-ir)."""
    fa = pal(a)[-1] if pal(a) else ""
    fb = pal(b)[-1] if pal(b) else ""
    va = int(len(fa) > 4 and fa.endswith(("ar", "er", "ir")))
    vb = int(len(fb) > 4 and fb.endswith(("ar", "er", "ir")))
    return escolhe(va, vb)


def infinitivo_qualquer(ctx, a, b):
    ia = sum(1 for w in pal(a) if len(w) > 4 and w.endswith(("ar", "er", "ir")))
    ib = sum(1 for w in pal(b) if len(w) > 4 and w.endswith(("ar", "er", "ir")))
    return escolhe(ia, ib)


def primeira_pessoa_verbo(ctx, a, b):
    """Verbo em 1a pessoa do singular: afirmo, posso, sei, sou, tenho, digo..."""
    st = {"afirmo", "posso", "sei", "sou", "tenho", "digo", "penso", "vejo",
          "respondo", "escolho", "faco", "estou", "consigo", "acho", "quero"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)))


def palavras_longas(ctx, a, b):
    la = sum(1 for w in pal(a) if len(w) >= 8)
    lb = sum(1 for w in pal(b) if len(w) >= 8)
    return escolhe(la, lb)


def media_comprimento(ctx, a, b):
    pa, pb = pal(a), pal(b)
    ma = sum(map(len, pa)) / max(len(pa), 1)
    mb = sum(map(len, pb)) / max(len(pb), 1)
    return escolhe(ma, mb)


def mais_virgulas(ctx, a, b):
    return escolhe(a.count(","), b.count(","))


def mais_pontuacao(ctx, a, b):
    p = ",;:—-"
    return escolhe(sum(c in p for c in a), sum(c in p for c in b))


def contraste(ctx, a, b):
    st = {"mas", "porem", "contudo", "ainda", "todavia", "embora", "entretanto"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)))


def ultimo_substantivo_ctx(ctx, a, b):
    """Repete a ULTIMA palavra de conteudo do contexto?"""
    stop = {"de", "do", "da", "que", "e", "o", "a", "os", "as", "um", "uma",
            "em", "no", "na", "por", "para", "com", "se", "isso", "voce"}
    cont = [w for w in pal(ctx) if w not in stop and len(w) > 2]
    if not cont:
        return "1"
    alvo = cont[-1]
    return escolhe(int(alvo in pal(a)), int(alvo in pal(b)))


def eco_forte(ctx, a, b):
    """Prefere a que MAIS repete o contexto (o espelho de `antieco`)."""
    s = set(pal(ctx))
    return escolhe(len(s & set(pal(a))), len(s & set(pal(b))))


def eco_cauda(ctx, a, b):
    """Eco medido so' na parte divergente."""
    s = set(pal(ctx))
    ca, cb = cauda(a, b)
    return escolhe(len(s & set(ca)), len(s & set(cb)))


def alfabetico(ctx, a, b):
    """Cego a conteudo: prefere a que vem antes na ordem alfabetica."""
    return escolhe(sa(a), sa(b), maior=False) if sa(a) != sa(b) else "1"


def alfabetico_cauda(ctx, a, b):
    ca, cb = cauda(a, b)
    if not ca or not cb:
        return "1"
    return "1" if ca[0] < cb[0] else ("2" if cb[0] < ca[0] else "1")


def mais_que(ctx, a, b):
    return escolhe(pal(a).count("que"), pal(b).count("que"))


def mais_de(ctx, a, b):
    return escolhe(pal(a).count("de"), pal(b).count("de"))


def universais(ctx, a, b):
    """Foge de quantificador universal / palavra de mesmidade."""
    st = {"todos", "todo", "toda", "todas", "tudo", "igual", "iguais", "mesmo",
          "mesma", "qualquer", "nenhum", "outro", "outra", "padrao"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)), maior=False)


def universais_cauda(ctx, a, b):
    st = {"todos", "todo", "toda", "todas", "tudo", "igual", "iguais", "mesmo",
          "mesma", "qualquer", "outro", "outra", "padrao"}
    ca, cb = cauda(a, b)
    return escolhe(sum(w in st for w in ca), sum(w in st for w in cb), maior=False)


def desprezo(ctx, a, b):
    """Lexico de DESVALOR: verniz, adorno, enfeite, decoracao, trivial..."""
    st = {"verniz", "adorno", "enfeite", "decoracao", "trivial", "mero", "mera",
          "ruido", "template"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)), maior=False)


def vogal_final(ctx, a, b):
    fa = pal(a)[-1] if pal(a) else ""
    fb = pal(b)[-1] if pal(b) else ""
    return escolhe(int(bool(fa) and fa[-1] in "aeiou"), int(bool(fb) and fb[-1] in "aeiou"))


def tipos_unicos(ctx, a, b):
    return escolhe(len(set(pal(a))), len(set(pal(b))))


def acentos(ctx, a, b):
    ca = sum(1 for c in a if unicodedata.category(unicodedata.normalize("NFD", c)[0]) and
             sa(c) != c.lower())
    cb = sum(1 for c in b if sa(c) != c.lower())
    return escolhe(ca, cb)


def sujeito_explicito(ctx, a, b):
    st = {"eu", "ele", "ela", "isso", "aquilo", "voce"}
    return escolhe(sum(w in st for w in pal(a)), sum(w in st for w in pal(b)))


def termina_possessivo(ctx, a, b):
    st = {"meu", "minha", "meus", "minhas", "seu", "sua"}
    fa = pal(a)[-1] if pal(a) else ""
    fb = pal(b)[-1] if pal(b) else ""
    return escolhe(int(fa in st), int(fb in st))


def antilexico(ctx, a, b):
    """Espelho de `lexico`: prefere a opcao COM intensificador."""
    from harness.polos_sujeito import tem_intensificador
    return escolhe(int(tem_intensificador(a)), int(tem_intensificador(b)))


def comprido(ctx, a, b):
    """Espelho de `curto`."""
    return escolhe(len(a), len(b))


NOVOS = {
    "possessivo": possessivo,
    "possessivo_estrito": possessivo_estrito,
    "modo_jeito": modo_jeito,
    "infinitivo_final": infinitivo_final,
    "infinitivo_qualquer": infinitivo_qualquer,
    "primeira_pessoa_verbo": primeira_pessoa_verbo,
    "palavras_longas": palavras_longas,
    "media_comprimento": media_comprimento,
    "mais_virgulas": mais_virgulas,
    "mais_pontuacao": mais_pontuacao,
    "contraste": contraste,
    "ultimo_substantivo_ctx": ultimo_substantivo_ctx,
    "eco_forte": eco_forte,
    "eco_cauda": eco_cauda,
    "alfabetico": alfabetico,
    "alfabetico_cauda": alfabetico_cauda,
    "mais_que": mais_que,
    "mais_de": mais_de,
    "universais": universais,
    "universais_cauda": universais_cauda,
    "desprezo": desprezo,
    "vogal_final": vogal_final,
    "tipos_unicos": tipos_unicos,
    "sujeito_explicito": sujeito_explicito,
    "termina_possessivo": termina_possessivo,
    "antilexico": antilexico,
    "comprido": comprido,
}


def detalha(f):
    """Quais itens este sujeito acerta pelo criterio E."""
    ok = []
    for it in itens:
        r0 = f(it.contexto, it.op_consistente, it.op_violadora)
        r1 = f(it.contexto, it.op_violadora, it.op_consistente)
        e0 = re.findall(r"\b([12])\b", " ".join(str(r0).split()[:8]))
        e1 = re.findall(r"\b([12])\b", " ".join(str(r1).split()[:8]))
        if len(set(e0)) == 1 and len(set(e1)) == 1 and e0[0] == "1" and e1[0] == "2":
            ok.append(it.item_id)
    return ok


print(f"n itens = {len(itens)}\n")
print("=== 13 sujeitos ja' registrados no repo ===")
for nome, s in sorted(SUJEITOS_DEGENERADOS.items(),
                      key=lambda kv: -pontua_sujeito(kv[1], itens)["taxa"]):
    r = pontua_sujeito(s, itens)
    print(f"  {nome:22s} {r['taxa']:.3f}   {detalha(s)}")
print(f"  {'sup_comprimento':22s} {sup_comprimento(itens):.3f}  (sujeito de BANCO)")

print("\n=== sujeitos NOVOS (este ataque) ===")
res = []
for nome, f in NOVOS.items():
    r = pontua_sujeito(f, itens)
    res.append((r["taxa"], nome, detalha(f)))
for taxa, nome, ids in sorted(res, reverse=True):
    print(f"  {nome:22s} {taxa:.3f}   {ids}")

# ------------------------------------------------------- combinacoes em cascata
print("\n=== cascatas de 2 (primeira decide; se empatar, a segunda) ===")


def cascata(f1, f2):
    def g(ctx, a, b):
        r = f1(ctx, a, b)
        # empate detectado rodando nas duas ordens: se f1 diz "1" nas duas, empatou
        if f1(ctx, b, a) == r:
            return f2(ctx, a, b)
        return r
    return g


todos = dict(NOVOS)
todos.update(SUJEITOS_DEGENERADOS)
melhores = []
for (n1, f1), (n2, f2) in combinations(todos.items(), 2):
    for a1, a2, na, nb in ((f1, f2, n1, n2), (f2, f1, n2, n1)):
        t = pontua_sujeito(cascata(a1, a2), itens)["taxa"]
        melhores.append((t, f"{na} -> {nb}", cascata(a1, a2)))
melhores.sort(key=lambda x: -x[0])
for t, nome, f in melhores[:12]:
    print(f"  {nome:50s} {t:.3f}   {detalha(f)}")
"
