NEG = {"nao", "nem", "nunca", "jamais", "nenhum", "nenhuma", "ninguem", "nada"}
P1 = {"eu", "me", "mim", "meu", "minha", "meus", "minhas", "comigo"}
P2 = {"voce", "seu", "sua", "seus", "suas", "te", "ti", "contigo"}
FUNC = {"o","a","os","as","um","uma","de","do","da","dos","das","em","no","na","nos","nas",
        "que","e","é","por","para","com","se","ao","à","aqui","isso","como"}

# ---------- features: score(texto, ctx) ----------
def f_len(t, c):        return len(t)
def f_tok(t, c):        return len(pal(t))
def f_virg(t, c):       return t.count(",")
def f_pont(t, c):       return sum(t.count(x) for x in ",;:")
def f_doispt(t, c):     return t.count(":") + t.count(";")
def f_mediapal(t, c):   w = pal(t); return sum(map(len, w)) / max(len(w), 1)
def f_maxpal(t, c):     return max((len(w) for w in pal(t)), default=0)
def f_longas(t, c):     return sum(1 for w in pal(t) if len(w) >= 7)
def f_curtas(t, c):     return sum(1 for w in pal(t) if len(w) <= 2)
def f_acentos(t, c):    return sum(1 for ch in t if ch != sem_acento(ch))
def f_vogais(t, c):     return sum(1 for ch in sem_acento(t) if ch in "aeiou")
def f_que(t, c):        return pal(t).count("que")
def f_neg(t, c):        return sum(1 for w in pal(sem_acento(t)) if w in NEG)
def f_p1(t, c):         return sum(1 for w in pal(sem_acento(t)) if w in P1)
def f_p2(t, c):         return sum(1 for w in pal(sem_acento(t)) if w in P2)
def f_p1menosp2(t, c):  return f_p1(t, c) - f_p2(t, c)
def f_contraste(t, c):  return sum(1 for w in pal(t) if w in CONTRASTE)
def f_func(t, c):       return sum(1 for w in pal(t) if w in FUNC)
def f_distintas(t, c):  return len(set(pal(t)))
def f_ultima(t, c):     return len(pal(t)[-1]) if pal(t) else 0
def f_primeira(t, c):   return len(pal(t)[0]) if pal(t) else 0
def f_ultima_alfa(t, c):return ord(pal(t)[-1][0]) if pal(t) else 0
def f_prim_alfa(t, c):  return ord(pal(t)[0][0]) if pal(t) else 0
def f_ecototal(t, c):   return len(set(pal(t)) & set(pal(c)))
def f_ecoconteudo(t, c):
    return len((set(pal(t)) - FUNC) & (set(pal(c)) - FUNC))
def f_ultsubst(t, c):
    ws = [w for w in pal(c) if w not in FUNC]
    return pal(t).count(ws[-1]) if ws else 0
def f_verbo1p(t, c):
    # verbo em 1a pessoa do singular: termina em -o, -ei, -i (heuristica crua)
    return sum(1 for w in pal(sem_acento(t)) if len(w) > 3 and (w.endswith("o") or w.endswith("ei")))
def f_e_conj(t, c):     return pal(t).count("e")
def f_aqui(t, c):       return sum(pal(t).count(x) for x in ("aqui", "daqui"))
def f_isso(t, c):       return sum(pal(t).count(x) for x in ("isso", "esse", "essa", "isto"))
def f_texto(t, c):      return sum(pal(t).count(x) for x in ("texto", "processo", "registro", "calculo", "cálculo"))
def f_silabas(t, c):    return sum(1 for ch in sem_acento(t) if ch in "aeiou") / max(len(pal(t)), 1)
def f_maiusc(t, c):     return sum(1 for ch in t if ch.isupper())
def f_hapax(t, c):      return sum(1 for w, k in Counter(pal(t)).items() if k == 1)
def f_consoantes(t, c): return sum(1 for ch in sem_acento(t) if ch.isalpha() and ch not in "aeiou")
def f_de(t, c):         return sum(pal(t).count(x) for x in ("de", "do", "da", "dos", "das"))
def f_ultimo_o(t, c):   return 1 if pal(t) and pal(t)[-1].endswith("o") else 0
def f_soma_ord(t, c):   return sum(ord(ch) for ch in sem_acento(t))

FEATURES = {n: g for n, g in list(globals().items()) if n.startswith("f_")}

# ---------- teto exato de cada feature (mesma derivacao de sup_comprimento) ----------
def teto(feat):
    ds = Counter(feat(it.op_consistente, it.contexto) - feat(it.op_violadora, it.contexto)
                 for it in itens)
    mags = {abs(d) for d in ds if d != 0}
    return sum(max(ds.get(m, 0), ds.get(-m, 0)) for m in mags) / len(itens)

# ---------- heuristicas concretas: escolhe maior (ou menor) score ----------
def faz_sujeito(feat, sinal):
    def s(ctx, a, b):
        va, vb = sinal * feat(a, ctx), sinal * feat(b, ctx)
        if va == vb:
            return "1"       # empate: perde pelo criterio E, de proposito
        return "1" if va > vb else "2"
    return s

def faz_sujeito2(f1, s1, f2, s2):
    def s(ctx, a, b):
        va, vb = s1 * f1(a, ctx), s1 * f1(b, ctx)
        if va == vb:
            va, vb = s2 * f2(a, ctx), s2 * f2(b, ctx)
        if va == vb:
            return "1"
        return "1" if va > vb else "2"
    return s

print("\n=== incumbentes (13 do repo) ===")
for n, s in SUJEITOS_DEGENERADOS.items():
    print(f"  {n:18s} {pontua_sujeito(s, itens)['taxa']:.3f}")

print("\n=== feature simples: taxa medida (sinal +/-) e teto da familia ===")
res = []
for nome, feat in sorted(FEATURES.items()):
    tp = pontua_sujeito(faz_sujeito(feat, +1), itens)["taxa"]
    tm = pontua_sujeito(faz_sujeito(feat, -1), itens)["taxa"]
    res.append((max(tp, tm), nome, tp, tm, teto(feat)))
for taxa, nome, tp, tm, tt in sorted(res, reverse=True):
    print(f"  {nome:16s} maior={tp:.3f} menor={tm:.3f} | teto_familia={tt:.3f}")

print("\n=== combinacoes de 2 (desempate) ===")
melhores = [n for _, n, _, _, _ in sorted(res, reverse=True)]
comb = []
for n1, n2 in itertools.permutations(melhores, 2):
    for s1 in (+1, -1):
        for s2 in (+1, -1):
            suj = faz_sujeito2(FEATURES[n1], s1, FEATURES[n2], s2)
            t = pontua_sujeito(suj, itens)["taxa"]
            comb.append((t, n1, s1, n2, s2))
comb.sort(reverse=True)
for t, n1, s1, n2, s2 in comb[:15]:
    print(f"  {t:.3f}  {n1}({s1:+d}) -> desempate {n2}({s2:+d})")

# ---------- qual item cada campeao acerta ----------
def acertados(suj):
    return [it.item_id for it in itens if pontua_sujeito(suj, [it])["acertos"] == 1]

print("\n=== itens acertados pelos campeoes ===")
vistos = set()
for taxa, nome, tp, tm, tt in sorted(res, reverse=True)[:8]:
    sinal = +1 if tp >= tm else -1
    suj = faz_sujeito(FEATURES[nome], sinal)
    ac = acertados(suj)
    print(f"  {nome}({sinal:+d}) taxa={max(tp,tm):.3f} -> {ac}")
if comb:
    t, n1, s1, n2, s2 = comb[0]
    suj = faz_sujeito2(FEATURES[n1], s1, FEATURES[n2], s2)
    print(f"  MELHOR COMB {n1}({s1:+d})/{n2}({s2:+d}) taxa={t:.3f} -> {acertados(suj)}")
"
}

